// hasOpKind reports whether any op in subitems matches kind. Used by
// the level-2 template to suppress an empty Triggers/Actions heading.
func hasOpKind(ops []PaletteOp, kind string) bool {
	for _, op := range ops {
		if op.Kind == kind {
			return true
		}
	}
	return false
}

// paletteDefaultsJSON encodes the op defaults as JSON for the
// data-node-defaults attribute. Returns "{}" on marshal failure so the
// attribute always parses cleanly client-side.
func paletteDefaultsJSON(d map[string]any) string {
	if len(d) == 0 {
		return "{}"
	}
	b, err := json.Marshal(d)
	if err != nil {
		return "{}"
	}
	return string(b)
}

